-- Enrichment marathon batch: TheFork Manager, TheHive, Thelia, Theneo, TheraNest, Thingsboard, Thinkific, Thinkific Plus

-- ── TheFork Manager ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TheFork Manager is the restaurant reservation, table management and marketing platform built by TheFork, the Paris-based, TripAdvisor-owned dining brand, for independent restaurants and multi-venue groups.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$German$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$TheFork Manager Review 2026: Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how TheFork Manager helps restaurants manage reservations, tables and guest marketing, plus its Performance and Enterprise pricing tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TheFork Manager is a restaurant management software product built by TheFork, the Paris-headquartered online dining platform founded in 2007 by Bertrand Jelensperger and Stevan Premutico (originally as LaFourchette) and majority-owned by TripAdvisor since 2014. TheFork Manager gives independent restaurants and restaurant groups a single dashboard to handle reservations arriving from TheFork's own consumer app, TripAdvisor, the Michelin Guide, Google, Instagram and Facebook, alongside a smart digital floorplan for table and shift optimization. The product bundles no-show protection tools such as credit-card guarantees, prepayments and automated reconfirmations, a guest CRM with segmentation and loyalty features, AI-assisted review summarization and guest messaging, and performance analytics benchmarked against comparable venues. It also connects to point-of-sale and CRM systems so guest data and spend history sync automatically. TheFork Manager is sold in two tiers, Performance and Enterprise, both quoted on request rather than published as flat monthly fees; restaurants are instead charged a commission on the average bill for guests who book through TheFork, TripAdvisor or partner channels, while bookings sourced through the restaurant's own website, Instagram or Facebook carry no additional commission. The Enterprise tier adds centralized multi-venue data, cross-selling between locations in a group, tailored email campaign tools and a group-level performance dashboard, aimed at restaurant chains and hospitality groups rather than single sites. Competitors in this category include SevenRooms, OpenTable for Restaurants, Resy OS and Tock, and restaurants often choose TheFork Manager specifically because it plugs into TheFork's large European diner audience, making it strongest for restaurants in France, Italy, Spain and other markets where TheFork has significant consumer reach.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fd454fe2-fd4b-4e4f-9816-8a9c32182617';

