-- ── TheHive ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TheHive is a Security Incident Response Platform built by StrangeBee for SOC, CERT and CSIRT teams to triage alerts, manage cases and collaborate on investigations; not to be confused with Apache Hive or unrelated project-management apps also named Hive.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community edition, self-hosted)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$TheHive Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$TheHive is StrangeBee's incident response platform for SOC and CERT teams. See its case management features, Cortex integration and pricing tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TheHive is a Security Incident Response Platform originally released in 2016 by Thomas Franco, Nabil Adouani and Jerome Leonard, three former CERT-BDF analysts, as a free open-source alternative for security operations centers, CERTs and CSIRTs. In 2018 the same three creators founded StrangeBee, a Paris-based cybersecurity company, to formalize development and support of TheHive alongside its companion analysis engine Cortex. TheHive gives analysts a shared case-management workspace: alerts imported from SIEMs, email and other detection sources can be triaged and escalated into cases, cases are broken into tasks and observables, and multiple analysts can work the same investigation simultaneously with full audit history. Cortex integration lets teams automatically enrich observables such as IPs, hashes and domains against threat-intel feeds and sandboxes, while MISP integration lets teams import indicators of compromise from MISP events or push their own findings back to sharing communities. With TheHive 5, StrangeBee shifted from a purely open-source model to a mixed one: a free Community edition remains available for on-premises deployments with core incident-response functionality, while Gold and Platinum editions are commercial annual subscriptions priced by number of users and organizations, unlocking advanced automation, larger multi-tenancy and premium support; StrangeBee also offers a fully managed TheHive Cloud Platform, though the Community edition is on-prem only. Earlier open-source releases, TheHive 3 and 4, remain in legacy use, though public availability of those older builds ended in 2025. TheHive is commonly compared to commercial SOAR and case-management tools such as IBM QRadar SOAR and Palo Alto Cortex XSOAR, and its main differentiator is deep, free-tier MISP interoperability plus a large base of community-built Cortex analyzers and responders, with more than 300 integrations built up since 2016.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '257eca99-6ff2-4447-96da-fbf120b70160';

