-- ── Thelia ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Thelia is a French open-source e-commerce platform built on the Symfony framework, maintained by digital agency OpenStudio, offering a free, self-hosted alternative to Shopify or PrestaShop for B2B, B2C and omnichannel stores.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Clermont-Ferrand, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Thelia Review 2026: Open-Source Ecommerce Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Thelia is a free, open-source French ecommerce platform built on Symfony. See its B2B, omnichannel and marketplace features plus how pricing works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Thelia is a free, open-source e-commerce platform created in 2005 by Cedric Sibaud and Yoan de Macedo and released under an open license in 2006; today it is maintained by OpenStudio, a French web agency also founded in 2005 and headquartered in Clermont-Ferrand with additional offices in Toulouse, Paris and Lyon. Thelia's current major version, Thelia 2, is built on the Symfony PHP framework and licensed under LGPL, giving developers full source-code access and freedom to self-host, modify and extend the platform without licensing fees. The software targets merchants and agencies who need deep customization beyond what closed SaaS platforms like Shopify allow: it exposes a REST API and templating system that support ERP and CRM integration, click-and-collect and drive or curbside pickup, in-store order picking with barcode scanning, B2B storefronts with client-specific pricing and payment terms, multisite management from one back office, product information management, and marketplace connections. A module marketplace with roughly 300 extensions lets teams add payment gateways, shipping carriers and marketing tools, and Thelia reports more than 7,000 live websites running on the platform, concentrated mostly in France and other French-speaking markets. Because Thelia itself is free software, most of the cost for a Thelia store comes from hosting, developer time, premium modules and themes, and optional professional services or support contracts sold by OpenStudio and its partner agencies rather than from Thelia licensing fees. Thelia competes most directly with other open-source carts such as PrestaShop, also French-built, and with WooCommerce, and with hosted platforms like Shopify, and is typically chosen by businesses that want full code ownership, Symfony-based extensibility, or complex B2B and omnichannel logic that off-the-shelf SaaS carts do not handle well out of the box.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3dd97986-493e-470c-90a6-4ef415e3a585';

