-- ── Theneo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Theneo is an AI-powered API documentation platform, founded by Maria Doliashvili and Ana Robakidze, that auto-generates, maintains and publishes interactive developer docs from OpenAPI, Postman, GraphQL and other API specs.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Theneo Review 2026: AI API Documentation Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Theneo auto-generates AI-powered API docs from OpenAPI and Postman specs. Compare its Starter, Business, Growth and Enterprise pricing plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Theneo is an AI-powered API documentation platform built by Theneo Inc, a company founded around 2021 by Maria Doliashvili and Ana Robakidze and graduated from Y Combinator's Winter 2022 batch; the company is headquartered in San Francisco with an engineering team based in Tbilisi, Georgia, and has raised early-stage funding including from Y Combinator. Theneo's core pitch, as covered by TechCrunch in 2022, is bringing Stripe-quality API documentation to teams that lack dedicated technical writers: it ingests OpenAPI/Swagger 2.0 and 3.x specs, Postman collections, GraphQL SDL or introspection, gRPC proto files, SOAP/WSDL and AsyncAPI definitions, then uses AI to generate readable descriptions, keep examples current, and flag documentation that has drifted from the live API. Beyond auto-generation, Theneo offers an interactive API Explorer for testing endpoints directly from the docs, AI-assisted search, automatic changelog generation when specs change, and authenticated developer-hub portals where individual customers can log in, with SSO available, and see only the APIs and SDKs relevant to them. Pricing runs on a freemium model: the Starter plan is free and includes one public and two private projects with a capped number of AI documentation builds and searches; Business is a paid workspace plan at 120 dollars per month billed annually, or 150 dollars month-to-month, adding more projects, custom branding, a custom domain and a developer hub; Growth, at 400 dollars per month annually or 450 dollars monthly, adds multiple developer hubs, custom CSS, advanced security and IP whitelisting; and Enterprise is custom-priced and adds self-hosting, SAML SSO, OAuth 2.0 and custom roles. Theneo is most often compared to Mintlify, ReadMe and Redocly as competing AI-era API documentation tools, differentiating itself primarily through its breadth of supported spec formats and its AI-driven documentation-drift detection.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '87dcb1df-40ff-447f-9953-e64d1561e834';

