-- ── TheraNest ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TheraNest, now operating as Ensora Mental Health under Ensora Health, is a practice management and EHR platform for therapists, counselors, psychologists and social workers, covering scheduling, notes, telehealth and billing.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$29/therapist/month (Essentials plan)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Birmingham, Alabama, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TheraNest Review 2026: Pricing, Features and Ensora Rebrand$q$, seo_title),
  seo_meta_description = COALESCE($q$TheraNest (now Ensora Mental Health) offers therapy scheduling, notes, billing and telehealth. Compare its Essentials, Advanced and Premier pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TheraNest is a practice management and electronic health record platform for behavioral and mental health providers, founded in 2013 in Birmingham, Alabama by Shegun Otulana. The product was later acquired into Therapy Brands, a portfolio company that private equity firm KKR bought for roughly 1.25 billion dollars in May 2021; in April 2025 Therapy Brands rebranded its whole portfolio to Ensora Health, and TheraNest itself was renamed Ensora Mental Health, though many customers and search listings still refer to it by the original TheraNest name. The platform covers the standard outpatient therapy workflow: appointment scheduling with automated no-show fee enforcement, a secure client portal, calendar sync, structured SOAP notes and a customizable Dynamic Form Builder for intake and progress notes, telehealth video sessions, e-prescribing, insurance billing with clearinghouse connections and ERA posting, and an AI Session Assistant that helps draft session documentation. TheraNest is priced per therapist per month across three tiers: Essentials at 29 dollars covers scheduling, the client portal and basic AI-enhanced notes; Advanced at 59 dollars adds online booking, secure messaging, custom forms and a monthly allotment of free claims processing and reminders; and Premier at 89 dollars adds unlimited claims processing, eligibility checks and reminders plus the Wiley Practice Planner content library. Paying annually reduces the effective monthly price to 27, 54 and 82 dollars respectively. Add-ons include the AI Session Assistant at 35 dollars per provider per month, telehealth for Essentials subscribers at 12 dollars per therapist, and e-prescribing with PDMP checks at 45 dollars per therapist plus a one-time setup fee. TheraNest competes with SimplePractice, TherapyNotes and TherapyAppointment in the mental-health-specific EHR category, and is generally positioned as a mid-market option with strong billing automation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5fbb1de8-79fd-408f-ab12-959b5b74f712';

