-- ── Thingsboard ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ThingsBoard is an open-source IoT platform for device management, data collection, processing and visualization, offered as a free self-hosted Community Edition plus paid Professional Edition, Private Cloud and ThingsBoard Cloud tiers.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition, self-hosted)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ThingsBoard Review 2026: IoT Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$ThingsBoard is an open-source IoT platform. Compare its free Community Edition against paid Professional, Private Cloud and ThingsBoard Cloud pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ThingsBoard is an open-source Internet of Things platform for device management, telemetry data collection, rule-based processing and dashboard visualization, first released in 2016 and formalized as a company, ThingsBoard Inc, in 2018, headquartered in New York. The Community Edition is licensed under Apache 2.0, free to self-host with no cap on the number of devices, assets or messages, and includes core building blocks such as an MQTT/HTTP/CoAP-based transport layer, a visual rule engine for processing telemetry and triggering alarms or actions, multi-tenancy, and a library of more than 600 prebuilt, customizable dashboard widgets for building end-user IoT interfaces. Teams that need more than community support can move to the self-managed Professional Edition, sold as a monthly subscription starting around 10 dollars per month for a 10-device Maker plan and scaling to roughly 499 dollars per month for 1,000 devices on the Business plan, with extra devices billed at about 10 cents each; a one-time perpetual license is also available starting near 4,999 dollars. Organizations that prefer not to manage infrastructure can use ThingsBoard Cloud, a fully hosted SaaS billed by device and data-point volume, with a free tier covering 5 devices and 1 million data points per month, scaling up through Prototype, Pilot, Startup and Business plans to roughly 749 dollars per month for 1,000 devices and a billion monthly data points. For the largest deployments, ThingsBoard also offers a managed Private Cloud tier starting near 1,499 dollars per month for 5,000 devices, up to a custom Enterprise plan for 100,000-plus devices. ThingsBoard is commonly compared to other IoT platforms such as AWS IoT Core and Azure IoT Hub, and its main differentiator is the combination of a fully free, unrestricted open-source core with a clear, published upgrade path to commercial support and hosting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8e405b1d-8563-4f77-89f4-97e61f455d64';

