-- ── Thinkific ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Thinkific is a publicly traded (TSX: THNC) Vancouver-founded platform for creating and selling online courses, communities, memberships and coaching, used by independent creators and small businesses.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$36/month (Basic plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Vancouver, British Columbia, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Thinkific Review 2026: Pricing, Features and Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$Thinkific lets creators sell online courses, communities and memberships. Compare its Basic, Start, Grow and Plus pricing plans and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Thinkific is an online course and learning-commerce platform founded in 2012 in Vancouver, Canada by Greg Smith, Matt Payne and Miranda Lievers. The company went public on the Toronto Stock Exchange under the ticker THNC and today serves tens of thousands of course creators, coaches and small businesses who have collectively generated billions of dollars in sales through the platform. Thinkific lets users build and sell online courses, cohort-based communities, memberships, digital downloads, live coaching and webinars from a single branded site, without needing separate video hosting, payment processing or community software. Core platform capabilities include a drag-and-drop course builder, customizable website themes, quizzes and certificates, a built-in community and discussion feature, live lesson and coaching scheduling, email marketing and automation tools, and native or third-party checkout with, on paid plans, 0 percent Thinkific transaction fees in primary markets like the United States. As of 2026 Thinkific no longer offers a permanently free plan, instead giving new users a 14-day free trial before requiring a paid subscription; published tiers are Basic at 36 dollars per month billed annually or 49 dollars month-to-month, Start at 74 dollars per month annually or 99 dollars monthly, and Grow at 149 dollars per month annually or 199 dollars monthly, each unlocking more advanced marketing, community and integration features plus higher limits, alongside unlimited courses and students on every tier. Above Grow sits Thinkific Plus, a custom-priced enterprise tier covering multi-site management, CRM integrations such as Salesforce and HubSpot, bulk B2B selling, SCORM compliance, single sign-on and dedicated success management. Thinkific's main competitors are Kajabi, Teachable and Podia, and it is generally positioned as the more scalable, feature-complete option once a creator's course business grows beyond a hobby-level catalog.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6f813de0-d2a3-471f-a9eb-5435220544a4';

