-- ── Thinkific Plus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Thinkific Plus is the custom-priced enterprise tier of Thinkific, the Vancouver-founded, publicly traded online course platform, built for larger organizations running corporate training or customer education at scale; it is the same company as Thinkific, not a separate competitor.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Vancouver, British Columbia, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Thinkific Plus Review 2026: Enterprise Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Thinkific Plus is Thinkific's enterprise LMS tier for corporate training and customer education. See its multi-site, CRM and SSO features and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Thinkific Plus is the enterprise-grade tier of Thinkific, the Vancouver, Canada-founded and publicly traded (TSX: THNC) online course and learning-commerce platform originally launched in 2012 by Greg Smith, Matt Payne and Miranda Lievers. Where the standard Thinkific plans, Basic, Start and Grow, target individual creators and small businesses, Thinkific Plus is built for larger organizations that need to run corporate training, partner or customer education, or multi-brand course businesses at scale, and it is sold entirely on custom, quote-based pricing rather than published monthly tiers. Key capabilities that separate Plus from the standard product include support for multiple Thinkific sites managed from one organization, so a company can organize courses by department, brand or audience while keeping shared administration; native CRM integrations with Salesforce, HubSpot and similar platforms to sync learner data into sales and marketing workflows; bulk-sell checkout for selling course access in volume to other organizations or corporate clients; SCORM compliance and learning-path sequencing for structured corporate training; single sign-on for enterprise identity providers; an AI teaching assistant; enterprise-grade API access; and dedicated onboarding plus a named customer success manager rather than standard-tier support queues. Because every Thinkific Plus contract is custom-quoted based on student volume, number of sites, and required integrations, prospective customers must contact Thinkific's sales team directly to get pricing, and the company does not publish a starting price the way it does for its self-serve Basic, Start and Grow plans. Thinkific Plus competes with enterprise learning platforms such as Docebo and LearnUpon, and with corporate LMS vendors like Cornerstone OnDemand, differentiating itself through its roots in Thinkific's creator-friendly course-building tools combined with enterprise administration and integration features layered on top.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '87506dfb-5657-49d7-8e5e-045ff26172f8';

