INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$What is TheFork Manager used for?$q$, $q$It is restaurant management software for handling reservations, table planning, guest CRM and marketing in one system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$How much does TheFork Manager cost?$q$, $q$Pricing is custom and quoted by TheFork's sales team; reservations from TheFork and partner channels are charged a commission based on average bill per guest.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Does TheFork Manager charge commission on all bookings?$q$, $q$No. Commission applies to bookings from TheFork, TripAdvisor and partner channels, while bookings from the restaurant's own website, Instagram or Facebook are not commissioned.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Is TheFork Manager only for restaurants that use TheFork app?$q$, $q$No. It also manages bookings from TripAdvisor, the Michelin Guide, Google, and the restaurant's own website and social pages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$What is the difference between the Performance and Enterprise plans?$q$, $q$Enterprise includes everything in Performance plus multi-venue tools for restaurant groups, such as centralized data, cross-selling and group performance dashboards.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Does TheFork Manager integrate with POS systems?$q$, $q$Yes, it syncs guest data with point-of-sale and CRM systems the restaurant already uses.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Who owns TheFork Manager?$q$, $q$It is built by TheFork, a Paris-based company that is majority owned by TripAdvisor.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Is there a free trial for TheFork Manager?$q$, $q$TheFork does not publicly advertise a self-serve free trial; interested restaurants typically request a demo and custom quote.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Reducing No-Shows$q$, $q$An independent restaurant uses credit-card guarantees and automated reconfirmations to cut last-minute cancellations.$q$, $q$Independent restaurant owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Centralizing Multi-Location Operations$q$, $q$A restaurant group uses the Enterprise tier to manage reservations, data and marketing across all its venues from one dashboard.$q$, $q$Restaurant groups and hospitality chains$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Growing Discovery Bookings$q$, $q$A restaurant expands its visibility and bookings through TheFork's and TripAdvisor's diner audiences.$q$, $q$Restaurants seeking new customer acquisition channels$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Performance$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["Smart floorplan","No-show protection tools","Guest CRM and marketing toolbox","Standard analytics","POS/CRM sync","Mobile app management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["All Performance features","Multi-venue centralized data","Cross-selling between locations","Tailored email campaigns","Group performance dashboard"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$overview$q$, $q$What Is TheFork Manager$q$, 2, ARRAY[$q$TheFork Manager is the business-facing software that restaurants use to run the operational side of taking reservations through TheFork, a European online dining platform founded in Paris in 2007 and majority-owned by TripAdvisor since 2014. Instead of just listing a restaurant for diners to find, TheFork Manager gives the restaurant a single back-office dashboard for managing every reservation, regardless of whether it originated on TheFork's own app, TripAdvisor, the Michelin Guide, Google, the restaurant's own website, or its Instagram and Facebook pages.$q$, $q$The product is aimed at both independent restaurants and multi-location restaurant groups, and it positions itself less as a booking widget and more as an all-in-one operations layer that also touches marketing, guest relationship management and performance reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the center of TheFork Manager is a smart digital floorplan that helps restaurants optimize table assignments and turn times across services, paired with a centralized reservation inbox that pulls bookings from all connected channels into one view. No-show protection tools, including credit-card guarantees, prepayments and automated reconfirmation messages, are built in to reduce lost revenue from last-minute cancellations.$q$, $q$On the marketing and guest-relationship side, TheFork Manager includes a guest CRM with segmentation for building targeted campaigns and loyalty programs, AI-powered tools that summarize customer reviews and help staff respond to guest messages faster, and performance analytics that benchmark a restaurant's booking trends against similar venues. Integrations with POS and CRM systems keep guest profiles and spend history in sync across systems the restaurant already uses, and a mobile app lets managers adjust availability and bookings from the floor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd454fe2-fd4b-4e4f-9816-8a9c32182617', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TheFork Manager does not publish flat monthly prices. It is sold in two tiers, Performance and Enterprise, both quoted after a sales conversation based on the restaurant's size, location and reservation volume. Enterprise adds features aimed at restaurant groups, such as centralized multi-venue data, cross-selling between locations, tailored email campaigns and a group-level performance dashboard.$q$, $q$Instead of a fixed subscription covering all bookings, TheFork Manager charges restaurants a commission calculated as a percentage of the average bill per guest for reservations that come through TheFork, TripAdvisor or other partner channels. Reservations generated through the restaurant's own website, Instagram or Facebook page are not subject to this commission.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Case and Task Management$q$, $q$Structures investigations into cases with tasks, templates, and full audit history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Alert Triage from SIEM and Email$q$, $q$Imports alerts from SIEMs, email reports and other sources for analysts to escalate into cases.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Cortex Observable Enrichment$q$, $q$Runs automated analyzers against IPs, hashes and domains using threat-intel feeds and sandboxes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$MISP Threat Intelligence Integration$q$, $q$Imports IOCs from MISP events and exports findings back to sharing communities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Multi-Analyst Real-Time Collaboration$q$, $q$Multiple analysts can work the same case simultaneously with tracked changes.$q$, 4);
