INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Self-hosting requires Elasticsearch/Cassandra-class infrastructure and ops know-how$q$, 2);
