INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Steeper learning curve for teams without a dedicated security operations background$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$What is TheHive used for?$q$, $q$It is a Security Incident Response Platform used by SOC, CERT and CSIRT teams to manage and investigate security cases.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Is TheHive free?$q$, $q$The Community edition is free for self-hosted, on-premises use; Gold and Platinum are paid commercial subscriptions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$What is the difference between TheHive and Cortex?$q$, $q$TheHive is the case-management platform; Cortex is the companion engine that runs analyzers and active responses against observables.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Who makes TheHive?$q$, $q$TheHive is maintained by StrangeBee, a Paris-based cybersecurity company founded in 2018 by TheHive's original creators.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$What is the difference between TheHive Community, Gold and Platinum?$q$, $q$Community is free and on-prem only with core features; Gold and Platinum are paid subscriptions priced by users and organizations, adding advanced automation and support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Does TheHive integrate with MISP?$q$, $q$Yes, TheHive has native integration with MISP for importing and exporting threat indicators.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Can TheHive be self-hosted?$q$, $q$Yes, both the free Community edition and the paid editions support on-premises self-hosted deployment.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$What happened to TheHive 3 and 4?$q$, $q$Public availability of the legacy TheHive 3 and 4 open-source builds ended in 2025 as StrangeBee moved focus to TheHive 5.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$SOC Alert Triage$q$, $q$A security operations team imports SIEM alerts into TheHive and triages which ones escalate into full investigations.$q$, $q$Security operations center analysts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Multi-Analyst Incident Investigation$q$, $q$A CERT or CSIRT coordinates several analysts working the same case simultaneously with full audit history.$q$, $q$CERT and CSIRT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$MSSP Incident Response Service$q$, $q$A managed security service provider uses TheHive's multi-tenancy to run incident response for multiple client organizations.$q$, $q$Managed security service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Core case management","Alert triage","Cortex and MISP integration","On-prem self-hosted only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Gold$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Priced by users and organizations","Advanced automation","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Platinum$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Everything in Gold","Larger multi-tenancy","Highest support tier"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$Cloud Platform$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["Fully managed SaaS deployment","IaaS and SaaS options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$overview$q$, $q$What Is TheHive$q$, 2, ARRAY[$q$TheHive is a Security Incident Response Platform that gives security teams a shared workspace for managing cases, tasks and observables during an investigation. It began in 2016 as a free, open-source project from three former CERT-BDF analysts, and by 2018 those creators had formalized the project into a company, StrangeBee, based in Paris.$q$, $q$The platform is built for security operations centers, CERTs, CSIRTs and MSSPs that need to move from a raised alert to a documented, collaborative investigation quickly, with tight integration into the broader threat-intelligence ecosystem via MISP and the observable-analysis engine Cortex, both also maintained by StrangeBee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$TheHive's core is case and task management: alerts from SIEMs, email reports and other sources can be imported and triaged, then escalated into full cases broken into tasks, with reusable case templates for common incident types. Multiple analysts can work the same case at once, with a full history of changes for accountability and reporting.$q$, $q$Observable enrichment happens through Cortex, which runs analyzers against IPs, file hashes, domains and other indicators using external threat-intel sources and sandboxes, and through responders that can take active containment or notification actions. MISP integration lets teams pull in indicators of compromise from shared MISP events or export their own findings back out, and a library of more than 300 community-built integrations extends the platform further.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('257eca99-6ff2-4447-96da-fbf120b70160', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TheHive offers a free Community edition for self-hosted, on-premises deployments, covering core case management, alert triage and Cortex/MISP integration for teams that do not need advanced multi-tenancy or premium support.$q$, $q$Above that, TheHive Gold and Platinum are commercial annual subscriptions priced by the number of users and organizations (tenants) supported, available for on-prem or cloud deployment, and StrangeBee also sells a fully managed TheHive Cloud Platform and an MSSP license for partners. None of the paid tiers publish flat prices; StrangeBee quotes them directly based on team size and deployment needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Symfony-Based Architecture$q$, $q$Built on the Symfony PHP framework, giving developers a familiar, well-documented foundation to extend.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$REST API$q$, $q$Exposes a REST API for headless commerce, ERP/CRM integration and custom front-end builds.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$B2B Storefronts with Custom Pricing$q$, $q$Supports client-specific pricing policies, payment modes and delivery terms for wholesale selling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Click and Collect / Drive Fulfillment$q$, $q$Native support for omnichannel pickup models like click-and-collect and drive service.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Multisite Management$q$, $q$Manage multiple storefronts from a single Thelia back office.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Order Picking with Barcode Scanning$q$, $q$A dedicated picking interface with barcode scanning, label generation and order verification.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Module Marketplace$q$, $q$Around 300 community and commercial modules extend payments, shipping and marketing features.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$PIM and Marketplace Connections$q$, $q$Supports product information management and connections to third-party marketplaces.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Free and open source with full source-code ownership$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Built on the well-established Symfony PHP framework$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Strong B2B and omnichannel feature set out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Around 300 community and commercial modules available$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Nearly two decades of active development and maintenance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Smaller ecosystem and community than PrestaShop or WooCommerce internationally$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Requires PHP and Symfony development skills to customize and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Hosting, premium modules and support are separate costs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Documentation and community resources are stronger in French than English$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Not a fully managed SaaS, so merchants own infrastructure and updates$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$What is Thelia used for?$q$, $q$Thelia is an open-source platform for building and running online stores, including B2B, omnichannel and multisite setups.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Is Thelia free to use?$q$, $q$Yes, Thelia is free open-source software; costs come from hosting, developer time, premium modules and optional support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$What license is Thelia released under?$q$, $q$Thelia 2 is released under the LGPL license, after starting under GPL in 2006.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Who maintains Thelia?$q$, $q$Thelia is maintained by OpenStudio, a French web agency founded in 2005 and headquartered in Clermont-Ferrand.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$What framework is Thelia built on?$q$, $q$Thelia 2 is built on the Symfony PHP framework.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Does Thelia support B2B selling?$q$, $q$Yes, Thelia supports B2B storefronts with client-specific pricing, payment modes and delivery terms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$How many websites use Thelia?$q$, $q$Thelia reports more than 7,000 live websites running on the platform, mostly in French-speaking markets.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$What is the difference between Thelia and PrestaShop?$q$, $q$Both are open-source, French-built e-commerce platforms; Thelia is built on Symfony with a strong B2B and omnichannel feature set, while PrestaShop has a larger international community.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Self-Hosted Store Launch$q$, $q$A French SMB launches a fully self-hosted online store without ongoing platform licensing fees.$q$, $q$Small and medium French businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Wholesale B2B Selling$q$, $q$A wholesale brand uses Thelia's B2B pricing and payment features to serve business customers alongside consumers.$q$, $q$B2B and wholesale brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Omnichannel Retail$q$, $q$A retailer implements click-and-collect and in-store order picking through Thelia's fulfillment tools.$q$, $q$Omnichannel retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Self-hosted deployment","Core e-commerce, B2B and multisite features","LGPL license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$Professional Services$q$, $q$Custom (via OpenStudio and partner agencies)$q$, $q$custom$q$, NULL, $q$["Implementation and development services","Premium modules and themes","Support contracts"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$overview$q$, $q$What Is Thelia$q$, 2, ARRAY[$q$Thelia is a free, open-source e-commerce platform that has been in continuous development since 2005, created by Cedric Sibaud and Yoan de Macedo and now maintained by the French web agency OpenStudio. Its current major version, Thelia 2, is built on the Symfony PHP framework and released under the LGPL license, meaning merchants and developers can self-host, inspect and modify the full source code without paying licensing fees.$q$, $q$Thelia is aimed at businesses and agencies that need more customization and code ownership than closed hosted platforms typically allow, and it has powered thousands of online stores in France and other French-speaking markets over nearly two decades.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Thelia exposes a REST API and flexible templating system that support a wide range of commerce models, including B2B storefronts with client-specific pricing and payment terms, multisite management from a single back office, and product information management for large catalogs.$q$, $q$Omnichannel retailers can use Thelia for click-and-collect and drive or curbside pickup, along with a dedicated order-picking interface featuring barcode scanning, label generation and order verification for in-store fulfillment. A module marketplace of roughly 300 extensions adds payment gateways, shipping carriers, marketplace connections and marketing tools on top of the core platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Thelia itself is free to download, install and use, since it is open-source software released under the LGPL license. There is no subscription fee or per-transaction charge from Thelia for running the core platform.$q$, $q$Real-world costs come from hosting infrastructure, developer time to build and maintain the store, premium modules or themes purchased from the marketplace, and optional professional services or support contracts from OpenStudio or partner agencies, which is how the maintaining company monetizes the ecosystem around the free software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3dd97986-493e-470c-90a6-4ef415e3a585', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$AI-Generated API Documentation$q$, $q$Automatically generates and updates documentation content from connected API specs.$q$, 0);
