INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Interactive API Explorer$q$, $q$Lets readers test API endpoints directly from within the documentation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Automatic Changelog Generation$q$, $q$Tracks and documents API changes automatically as specs evolve.$q$, 3);
