INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Custom Branding and Domains$q$, $q$Business-tier and above plans support custom branding, SEO settings and custom domains.$q$, 6);
