INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Some advanced features are workspace-limited rather than per-seat$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$What is Theneo used for?$q$, $q$Theneo is used to auto-generate, maintain and publish interactive API documentation from specs like OpenAPI and Postman.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Is Theneo free?$q$, $q$Yes, Theneo has a free Starter plan with limited public and private projects and capped AI usage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$What API spec formats does Theneo support?$q$, $q$Theneo supports OpenAPI/Swagger, Postman collections, GraphQL, gRPC, SOAP/WSDL and AsyncAPI.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Who founded Theneo?$q$, $q$Theneo was founded by Maria Doliashvili and Ana Robakidze and went through Y Combinator's Winter 2022 batch.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$What is the difference between Theneo Business and Growth plans?$q$, $q$Growth adds multiple developer hubs, custom CSS, advanced security and IP whitelisting on top of everything in Business.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Does Theneo offer self-hosting?$q$, $q$Self-hosting is available on Theneo's custom-priced Enterprise plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$How does Theneo compare to Mintlify?$q$, $q$Both are modern API documentation platforms; Theneo emphasizes AI-driven generation and broad spec-format support, including GraphQL, gRPC and SOAP.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Does Theneo support SSO?$q$, $q$SAML SSO and OAuth 2.0 are available on Theneo's Enterprise plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Docs Without a Technical Writer$q$, $q$A startup without a dedicated technical writer uses Theneo to auto-generate and maintain developer documentation.$q$, $q$Early-stage startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Per-Customer Developer Hubs$q$, $q$A B2B platform company gives each customer an authenticated hub showing only their relevant APIs and SDKs.$q$, $q$B2B SaaS and platform companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Multi-Format API Documentation$q$, $q$An API-first company documents REST, GraphQL and gRPC services together in one platform.$q$, $q$Engineering and developer relations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 public project","2 private projects","Up to 20 team members","Capped AI documentation builder and search usage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Business$q$, $q$$120/month/workspace (annual), $150/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 7 projects","Up to 50 team members","Unlimited AI search and doc builder","Custom branding and domain","One developer hub"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Growth$q$, $q$$400/month/workspace (annual), $450/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Business","Custom CSS","Up to 20 developer hubs","Advanced security and IP whitelisting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["Self-hosting","SAML SSO and OAuth 2.0","Custom user roles and permissions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$overview$q$, $q$What Is Theneo$q$, 2, ARRAY[$q$Theneo is an AI-powered platform for generating and maintaining API documentation. Founded around 2021 by Maria Doliashvili and Ana Robakidze and backed by Y Combinator's Winter 2022 batch, the company is headquartered in San Francisco with much of its engineering team based in Tbilisi, Georgia.$q$, $q$The product is built for teams that need Stripe-quality developer docs without dedicating a full-time technical writer to the job, connecting directly to a codebase or API spec to detect changes and keep documentation accurate over time rather than treating docs as a one-time export.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Theneo supports essentially every major API spec format, including OpenAPI/Swagger 2.0 and 3.x, Postman collections, GraphQL SDL and introspection, gRPC proto files, SOAP/WSDL and AsyncAPI, so teams can bring documentation in from whatever tooling they already use. Its AI features generate readable descriptions and examples, detect when documentation has drifted from the live API, and power an AI-assisted search experience for readers.$q$, $q$For teams selling APIs to other businesses, Theneo offers authenticated developer-hub portals where each customer signs in, with per-customer logins, email invites and SSO if needed, and sees only the APIs, guides and SDKs relevant to them. An interactive API Explorer lets readers test endpoints directly from the documentation, and automatic changelog generation keeps a record of what changed and when.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87dcb1df-40ff-447f-9953-e64d1561e834', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Theneo's Starter plan is free and includes one public project, two private projects, and capped usage of its AI documentation builder and search features, making it usable for small or early-stage API projects.$q$, $q$Paid plans scale by workspace: Business costs 120 dollars per month billed annually or 150 dollars month-to-month and adds more projects, custom branding, a custom domain and a developer hub; Growth costs 400 dollars per month annually or 450 dollars monthly and adds multiple developer hubs, custom CSS and advanced security controls; and Enterprise is custom-priced, adding self-hosting, SAML SSO, OAuth 2.0 and custom user roles for large organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Appointment Scheduling with No-Show Fees$q$, $q$Automated scheduling with built-in no-show fee enforcement and calendar sync.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Secure Client Portal$q$, $q$Lets clients book, message and complete intake forms through a secure portal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$SOAP Notes and Dynamic Form Builder$q$, $q$Structured clinical documentation with customizable intake and progress note templates.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Telehealth Video Sessions$q$, $q$Built-in video telehealth, available as a paid add-on on the Essentials plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Insurance Billing and Clearinghouse Integration$q$, $q$Claims processing, eligibility checks and ERA posting through connected clearinghouses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$AI Session Assistant$q$, $q$AI tool that helps clinicians draft session documentation faster.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$E-Prescribing with PDMP Checks$q$, $q$Electronic prescribing with prescription drug monitoring program checks, sold as an add-on.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Wiley Practice Planner Content$q$, $q$Included on the Premier plan, providing treatment-planning content for clinicians.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Transparent, published per-therapist pricing across three tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Purpose-built for mental and behavioral health workflows, not generic medical EHR$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Insurance billing automation reduces manual claims work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$AI Session Assistant speeds up documentation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Annual billing offers a meaningful discount over monthly pricing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Telehealth and e-prescribing are paid add-ons on lower tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Brand is transitioning to Ensora Mental Health, which can cause confusion$q$, 1);
