INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$AI and e-prescribing add-ons increase the effective monthly cost significantly$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Owned by a large private-equity-backed portfolio, which some independent practices may weigh when choosing a vendor$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$What is TheraNest used for?$q$, $q$It is practice management and EHR software for therapists covering scheduling, clinical notes, telehealth and insurance billing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$How much does TheraNest cost?$q$, $q$Plans start at 29 dollars per therapist per month for Essentials, up to 89 dollars for Premier, with a discount for annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Is TheraNest the same as Ensora Mental Health?$q$, $q$Yes, TheraNest was renamed Ensora Mental Health in April 2025 after its parent company Therapy Brands rebranded as Ensora Health.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Does TheraNest include telehealth?$q$, $q$Telehealth is included on Advanced and Premier plans and available as a paid add-on for Essentials subscribers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$What is the AI Session Assistant?$q$, $q$It is an add-on AI tool priced at 35 dollars per provider per month that helps clinicians draft session documentation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Does TheraNest handle insurance billing?$q$, $q$Yes, it includes claims processing, eligibility checks and ERA posting, with usage limits that increase by plan tier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$What is the difference between Essentials, Advanced and Premier?$q$, $q$Essentials covers core scheduling and notes, Advanced adds online booking and limited free billing usage, and Premier adds unlimited billing automation and the Wiley Practice Planner.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Who owns TheraNest?$q$, $q$TheraNest is owned by Ensora Health, formerly Therapy Brands, which KKR acquired in 2021.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Solo Therapist Practice Management$q$, $q$A solo therapist manages scheduling, clinical notes and billing in one platform instead of separate tools.$q$, $q$Solo mental health practitioners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Group Practice Billing Automation$q$, $q$A group therapy practice uses Premier-tier billing automation to reduce manual insurance claims work.$q$, $q$Group therapy practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Telehealth Counseling$q$, $q$A counselor offers telehealth sessions alongside in-person visits, using the client portal for scheduling.$q$, $q$Counselors offering remote and hybrid care$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Essentials$q$, $q$$29/therapist/month ($27/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Scheduling management","Secure client portal","Calendar sync","Basic intake forms and AI-enhanced notes","Optional telehealth add-on"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Advanced$q$, $q$$59/therapist/month ($54/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Essentials","Online booking and secure messaging","Custom intake forms and progress notes","30 free monthly claims, eligibility checks and reminders"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$Premier$q$, $q$$89/therapist/month ($82/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Advanced","Unlimited claims processing, eligibility checks and reminders","Wiley Practice Planner included","Unlimited telehealth"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$overview$q$, $q$What Is TheraNest$q$, 2, ARRAY[$q$TheraNest is a practice management and electronic health record platform built specifically for mental and behavioral health providers, founded in 2013 in Birmingham, Alabama by Shegun Otulana. It later became part of Therapy Brands, which KKR acquired for roughly 1.25 billion dollars in 2021, and in April 2025 the whole portfolio, including TheraNest, was rebranded as Ensora Health, with the product itself now marketed as Ensora Mental Health.$q$, $q$The platform is designed for solo therapists, group practices and behavioral health organizations that need scheduling, clinical documentation, telehealth and insurance billing in one system, rather than juggling separate tools for each function.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality covers appointment scheduling with automated no-show fee enforcement, a secure client portal, calendar sync, and clinical documentation through structured SOAP notes and a Dynamic Form Builder for custom intake and progress note templates. Telehealth video sessions and e-prescribing with PDMP checks round out the clinical side.$q$, $q$On the administrative side, TheraNest handles insurance billing with clearinghouse integration and ERA posting, and its AI Session Assistant helps clinicians draft session documentation faster. Higher tiers add the Wiley Practice Planner content library and unlimited claims processing and eligibility checks, aimed at practices that want to minimize manual billing work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fbb1de8-79fd-408f-ab12-959b5b74f712', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TheraNest is priced per therapist per month across three published tiers: Essentials at 29 dollars, Advanced at 59 dollars, and Premier at 89 dollars, each adding more billing automation, forms and content on top of the last. Paying annually includes one month free, bringing the effective monthly cost down to 27, 54 and 82 dollars respectively.$q$, $q$Several features are sold as add-ons rather than bundled into the base price: the AI Session Assistant costs 35 dollars per provider per month, telehealth for Essentials subscribers costs 12 dollars per therapist per month, and e-prescribing with PDMP checks costs 45 dollars per therapist per month plus a one-time setup fee. All plans include HIPAA compliance, unlimited clients, and complimentary billing and scheduling staff roles.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Apache 2.0 Community Edition$q$, $q$Free, open-source core platform with no device or message limits.$q$, 0);
