INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Visual Rule Engine$q$, $q$Processes telemetry and triggers alarms or downstream actions through a visual rule chain builder.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$600-Plus Customizable Dashboard Widgets$q$, $q$A large library of prebuilt widgets for building end-user IoT dashboards.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Multi-Tenancy$q$, $q$Supports isolating multiple tenants or business units within one deployment.$q$, 4);
