INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Device Management and Provisioning$q$, $q$Tools for provisioning, organizing and managing large fleets of connected devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Fully Hosted Cloud Option$q$, $q$ThingsBoard Cloud offers a managed SaaS deployment billed by device and data-point volume.$q$, 7);
