INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Professional Edition still requires manual server management, unlike full SaaS$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Some enterprise features are only available on Private Cloud or Enterprise plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Is ThingsBoard free?$q$, $q$The Community Edition is free and open source under Apache 2.0 with no device limits; paid tiers add support and enterprise features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$What is the difference between ThingsBoard Community and Professional Edition?$q$, $q$Professional Edition adds white labeling, advanced role management, Trendz Analytics and edge modules on top of the free Community Edition.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Does ThingsBoard offer a hosted cloud option?$q$, $q$Yes, ThingsBoard Cloud is a fully managed SaaS billed by device and data-point volume.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$What license does ThingsBoard use?$q$, $q$The Community Edition is licensed under Apache 2.0.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$How many devices can Community Edition support?$q$, $q$There is no device limit on the free Community Edition.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$What protocols does ThingsBoard support?$q$, $q$ThingsBoard supports MQTT, HTTP and CoAP for device connectivity.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Who makes ThingsBoard?$q$, $q$ThingsBoard is developed by ThingsBoard Inc, founded in 2016 and headquartered in New York.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$What is ThingsBoard Edge?$q$, $q$ThingsBoard Edge extends the platform's processing capabilities to gateways and edge hardware.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Self-Hosted IoT Backend$q$, $q$A hardware startup self-hosts the free Community Edition as the backend for its connected device fleet.$q$, $q$Hardware and IoT startups$q$, 0);
