INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Fully Managed IoT SaaS$q$, $q$A company avoids managing infrastructure by running its IoT solution entirely on ThingsBoard Cloud.$q$, $q$Teams without dedicated DevOps resources$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited devices, assets and messages","Apache 2.0 license","Self-hosted deployment","Community support"]$q$::jsonb, 0);
