INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Professional Edition (Business)$q$, $q$$499/month$q$, $q$monthly$q$, NULL, $q$["1,000 devices","3 production instances","White labeling and advanced roles"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$ThingsBoard Cloud (Free)$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["5 devices","5 assets","1M data points per month"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$ThingsBoard Cloud (Business)$q$, $q$$749/month$q$, $q$monthly$q$, NULL, $q$["1,000 devices","1,000 assets","1B data points per month"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$Private Cloud (Enterprise)$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["100,000+ devices","Unlimited messages per minute","Dedicated managed infrastructure"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$overview$q$, $q$What Is ThingsBoard$q$, 2, ARRAY[$q$ThingsBoard is an open-source IoT platform for connecting, managing and visualizing data from internet-connected devices. First released in 2016 and formalized as a company, ThingsBoard Inc, in 2018, it is headquartered in New York and maintains a large open-source Community Edition alongside several commercial deployment options.$q$, $q$The platform is used by teams building IoT products and internal fleets alike, from hardware startups self-hosting a free backend to enterprises running fully managed IoT dashboards through ThingsBoard's paid cloud and private cloud offerings.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, ThingsBoard connects devices over MQTT, HTTP and CoAP, then processes incoming telemetry through a visual rule engine that can trigger alarms, transformations or downstream actions. Multi-tenancy lets a single deployment serve multiple customers or business units in isolation, and ThingsBoard Edge extends processing to gateways and edge hardware.$q$, $q$For building user-facing dashboards, ThingsBoard ships with a library of more than 600 customizable widgets covering charts, maps, gauges and control panels, so teams can assemble IoT interfaces without building visualization components from scratch. Device provisioning and management tools round out the platform for teams operating large device fleets.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is free and open source under Apache 2.0, with no limit on the number of devices, assets or messages, making it a genuinely usable option for production deployments with community-only support.$q$, $q$Paid options scale from the self-managed Professional Edition, starting around 10 dollars per month for a 10-device Maker plan up to roughly 499 dollars per month for 1,000 devices on Business, to the fully hosted ThingsBoard Cloud, which has its own free tier and paid plans up to about 749 dollars per month, and a managed Private Cloud tier starting near 1,499 dollars per month for the largest deployments, with custom Enterprise pricing above that.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8e405b1d-8563-4f77-89f4-97e61f455d64', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
