INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$What is Thinkific used for?$q$, $q$Thinkific is used to build and sell online courses, communities, memberships and coaching products.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$How much does Thinkific cost?$q$, $q$Plans start at 36 dollars per month billed annually for Basic, up to 149 dollars per month for Grow, plus a custom-priced Plus tier.$q$, 1, 'published');
