INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$What is the difference between Thinkific Basic, Start and Grow?$q$, $q$Each tier unlocks more marketing, community and integration features and higher limits, with Grow offering the most advanced tools among the self-serve plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Does Thinkific charge transaction fees?$q$, $q$No, paid Thinkific plans charge 0 percent transaction fees in primary markets like the United States.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$What is Thinkific Plus?$q$, $q$Thinkific Plus is the custom-priced enterprise tier for larger organizations, sold separately from the self-serve plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Is Thinkific publicly traded?$q$, $q$Yes, Thinkific trades on the Toronto Stock Exchange under the ticker THNC.$q$, 6, 'published');
