INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$Plus$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["Multi-site management","CRM integrations","Bulk B2B selling","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$overview$q$, $q$What Is Thinkific$q$, 2, ARRAY[$q$Thinkific is an online learning-commerce platform founded in 2012 in Vancouver, Canada by Greg Smith, Matt Payne and Miranda Lievers, and it is now a publicly traded company on the Toronto Stock Exchange under the ticker THNC. The platform lets creators, coaches and small businesses build and sell online courses, communities, memberships and coaching products from one branded site.$q$, $q$Thinkific has grown from a simple course-hosting tool into a broader learning-commerce platform, adding communities, live coaching, memberships and digital downloads alongside its original course-building features, aimed at helping course creators diversify revenue beyond one-off course sales.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Thinkific is a drag-and-drop course builder combined with customizable website themes, quizzes, certificates and completion tracking, so creators can build a full branded learning site without code. A built-in community and discussion feature lets creators run cohort-based or ongoing communities alongside their courses.$q$, $q$Beyond courses, Thinkific supports memberships, digital downloads, live lessons and coaching scheduling, plus email marketing automation to nurture leads and re-engage students. On paid plans, Thinkific charges 0 percent transaction fees in primary markets like the United States, meaning creators keep more of each sale compared with platforms that take a cut per transaction.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6f813de0-d2a3-471f-a9eb-5435220544a4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$As of 2026, Thinkific no longer offers a permanently free plan, instead giving new users a 14-day free trial. Published self-serve plans are Basic at 36 dollars per month billed annually or 49 dollars month-to-month, Start at 74 dollars per month annually or 99 dollars monthly, and Grow at 149 dollars per month annually or 199 dollars monthly, with unlimited courses and students included on every tier.$q$, $q$Above Grow sits Thinkific Plus, a custom-priced enterprise tier for organizations that need multi-site management, CRM integrations, bulk selling and enterprise support; pricing for Plus is quoted directly by Thinkific's sales team rather than published.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Multi-Site Management$q$, $q$Run multiple Thinkific sites under one organization with shared administration.$q$, 0);
