INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$What is Thinkific Plus?$q$, $q$It is the custom-priced enterprise tier of Thinkific, built for larger organizations running training or education programs at scale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$How is Thinkific Plus different from regular Thinkific?$q$, $q$Plus adds multi-site management, CRM integrations, SCORM compliance, SSO and dedicated support beyond what the Basic, Start and Grow plans offer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$How much does Thinkific Plus cost?$q$, $q$Pricing is custom and quoted directly by Thinkific's sales team based on the organization's needs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Does Thinkific Plus support multiple sites?$q$, $q$Yes, Plus allows an organization to manage multiple Thinkific sites under one account.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Does Thinkific Plus integrate with Salesforce or HubSpot?$q$, $q$Yes, Thinkific Plus includes native CRM integrations with platforms like Salesforce and HubSpot.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Does Thinkific Plus support SCORM content?$q$, $q$Yes, SCORM compliance is included for structured corporate training content.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Who is Thinkific Plus for?$q$, $q$It is aimed at enterprises, software companies and multi-brand organizations running training or customer education at scale.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Does Thinkific Plus include single sign-on?$q$, $q$Yes, single sign-on for enterprise identity providers is included in Thinkific Plus.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Corporate Onboarding and Compliance Training$q$, $q$An enterprise uses Thinkific Plus to deliver onboarding and compliance training across departments.$q$, $q$Enterprise HR and learning and development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Customer Education at Scale$q$, $q$A software company runs customer education programs across multiple product lines using Thinkific Plus.$q$, $q$Software and SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Multi-Brand Course Management$q$, $q$A franchise or multi-brand organization manages separate course sites for each brand under one Thinkific Plus account.$q$, $q$Franchise and multi-brand organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$Plus$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["Multi-site management","CRM integrations","Bulk B2B checkout","SCORM compliance","Single sign-on","Dedicated onboarding and success manager"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$overview$q$, $q$What Is Thinkific Plus$q$, 2, ARRAY[$q$Thinkific Plus is the enterprise tier of Thinkific, the same Vancouver-founded, publicly traded company behind the standard Thinkific course platform. Rather than being a separate product from a different vendor, Plus is a custom-configured version of Thinkific built for organizations running training or education programs at a scale beyond what the self-serve Basic, Start and Grow plans are designed for.$q$, $q$Typical Thinkific Plus customers include companies delivering corporate onboarding and compliance training, software vendors running customer education programs, and multi-brand or franchise organizations that need to manage several course sites under one account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Thinkific Plus adds multi-site management so an organization can run several Thinkific sites, organized by brand, department or audience, from shared administration. Native CRM integrations with Salesforce, HubSpot and similar platforms sync learner activity into sales and marketing systems, and bulk-sell checkout supports selling course access in volume to corporate or partner clients.$q$, $q$For corporate training use cases, Plus adds SCORM compliance, learning-path sequencing, single sign-on for enterprise identity providers, an AI teaching assistant, and enterprise-grade API access. Plus customers also get dedicated onboarding and a named customer success manager rather than standard support queues.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('87506dfb-5657-49d7-8e5e-045ff26172f8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Thinkific Plus does not publish flat pricing. Every contract is custom-quoted based on factors like student volume, number of managed sites, and which integrations and enterprise features the organization needs, so prospective customers must contact Thinkific's sales team directly for a quote.$q$, $q$This differs from the standard Thinkific plans, which publish fixed monthly and annual prices for Basic, Start and Grow; Plus sits above Grow specifically for organizations whose needs, and budgets, exceed what a fixed self-serve tier can support.$q$]::text[], 2);
